}

function Chat() {
  useShowcaseHooks();
  useShowcaseSuggestions();

  return (
    <div className="flex h-full w-full">
      <div className="flex-1 flex justify-center items-center">
        <div className="h-full w-full md:w-4/5 md:h-4/5 rounded-lg px-6">
